local redis = require "resty.redis"
local cjson = require "cjson"

local function secure_load_code(code_string)
    if not code_string or type(code_string) ~= "string" then
        return nil, "Invalid code string"
    end
    
    -- Check for dangerous patterns
    local dangerous_patterns = {
        "package", "require", "io", "os", "load", "loadfile", "dofile",
        "collectgarbage", "debug", "rawset", "rawget", "setmetatable",
        "getmetatable", "pcall", "xpcall", "coroutine"
    }
    
    for _, pattern in ipairs(dangerous_patterns) do
        if string.find(code_string, pattern, 1, true) then
            return nil, "Forbidden pattern detected: " .. pattern
        end
    end
    
    -- Check for excessive length
    if #code_string > 10000 then
        return nil, "Code too long"
    end
    
    -- Check for balanced brackets
    local open_brackets = 0
    local close_brackets = 0
    
    for i = 1, #code_string do
        local char = string.sub(code_string, i, i)
        if char == "{" then
            open_brackets = open_brackets + 1
        elseif char == "}" then
            close_brackets = close_brackets + 1
        end
    end
    
    if open_brackets ~= close_brackets then
        return nil, "Unbalanced brackets"
    end
    
    local func, err = loadstring(code_string)
    if not func then
        return nil, "Load failed: " .. tostring(err)
    end
    
    return func
end

local function load_plugin_from_redis(plugin_key)
    local red = redis:new()
    red:set_timeout(1000)
    
    local ok, err = red:connect("127.0.0.1", 6379)
    if not ok then
        return nil, "Redis connection failed: " .. tostring(err)
    end
    
    local code, err = red:get(plugin_key)
    if not code then
        return nil, "Plugin not found: " .. tostring(err)
    end
    
    red:close()
    
    return secure_load_code(code)
end

local function load_plugin_from_header()
    local plugin_code = ngx.var.http_x_plugin_code
    if not plugin_code then
        return nil, "No plugin code in header"
    end
    
    return secure_load_code(plugin_code)
end

local function execute_plugin()
    local plugin_func, err = load_plugin_from_redis("api_gateway_plugin")
    if not plugin_func then
        plugin_func, err = load_plugin_from_header()
    end
    
    if not plugin_func then
        ngx.status = 400
        ngx.say("Plugin loading failed: " .. tostring(err))
        ngx.exit(400)
        return
    end
    
    local ok, result = pcall(plugin_func)
    if not ok then
        ngx.status = 500
        ngx.say("Plugin execution failed: " .. tostring(result))
        ngx.exit(500)
        return
    end
    
    ngx.say(cjson.encode(result))
end

execute_plugin()